class Rectangle {
  double width, height;
  Rectangle(this.width, this.height);

  double get area => width * height;

  set area(double value) {
    // Just for demonstration; normally you wouldn't set area directly.
    width = value / height;
  }
}

void main() {
  var rect = Rectangle(5, 10);
  print(rect.area); // 50.0
  rect.area = 100;
  print(rect.width); // 10.0
}
